{
    PropertyName = "@odata.type",
    Mapping = new Dictionary<string, OpenApiSchemaReference> {
        {
            "#microsoft.graph.directoryObject", new OpenApiSchemaReference("microsoft.graph.directoryObject")
        }
    }
}
```

